              {/* Hazmat & Evacuation */}
              {(result.hazmatAssessment?.present || result.evacuationPlan?.required) && (
                <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
                  {result.hazmatAssessment?.present && (
